parameters.jsCode:
// RAG Kontext aufbereiten
const chunks = $input.all();
const ticket = $('Zammad: Get Ticket Details').first().json;

if (chunks.length === 0) {
  return [{ json: { 
    hasContext: false,
    ragContext: '',
    sources: [],
    missingContext: [{ reason: 'Keine relevanten Wissensquellen gefunden' }]
  }}];
}

const ragContext = chunks.map((c, i) => 
  `[Quelle ${i+1}: ${c.json.document_title}]\n${c.json.chunk_text}`
).join('\n\n---\n\n');

const sources = chunks.map(c => ({
  document_id: c.json.document_id,
  title: c.json.document_title,
  source_uri: c.json.source_uri,
  similarity: c.json.similarity
}));

return [{ json: { hasContext: true, ragContext, sources, missingContext: [] } }];

