const response = $input.first().json;
const content = response.choices?.[0]?.message?.content;
let draft;
try { draft = JSON.parse(content); } catch(e) { throw new Error('Draft JSON invalid'); }

const ragCtx = $('Build RAG Context').first().json;
const ticketId = $('Webhook Trigger').first().json.zammad_ticket_id;
const analysisId = $('Webhook Trigger').first().json.analysis_id;

return [{ json: {
  ...draft,
  zammad_ticket_id: ticketId,
  analysis_id: analysisId,
  used_sources: ragCtx.sources,
  missing_context: ragCtx.missingContext,
  needs_human_approval: ragCtx.hasContext ? draft.needs_human_approval : true,
  tone: 'friendly',
  language: $('Load Analysis from DB').first().json.language
}}];

